task V3E_096 {
  require cap(relay1)
  set relay1 = 1
  wait 100ms
  readback relay1 expect 1

  repeat 3 times {
    if (device == "water_sensor") {
      read water_sensor
    } else if (device == "temperature_sensor") {
      read temperature_sensor
    } else if (device == "humidity_sensor") {
      read humidity_sensor
    }
  }

  set relay1 = 0
  wait 100ms
  readback relay1 expect 0

  halt
}
